//! Real auth, via a0n-auth (P-256 UCAN verify + revocation). This replaces
//! moonshine's cosmetic HMAC `validate_ucan`.
//!
//! Important inversion of the usual auth role: this is NOT a gate. badchild
//! admits everyone ("everyone gets through"). The auth finding is an *input* to
//! the policy, used only to decide the destination - never to return a 401. A
//! missing or invalid token does not bounce the caller; it just means they will
//! be misrouted into shadow rather than reaching the real target.

use a0n_auth::{verify_chain, RevocationSet};

use crate::policy::Subject;

/// What we learned about a caller's credentials. Feeds `policy::Subject`.
#[derive(Debug, Clone, Default)]
pub struct AuthFinding {
    /// The verified holder DID (leaf issuer), if the chain verified.
    pub holder: Option<String>,
    /// The root the chain traces back to, if any.
    pub root_issuer: Option<String>,
    /// Whether the delegation chain verified against the revocation set.
    pub valid: bool,
    /// Human-readable reason when invalid (never surfaced to the caller).
    pub reason: String,
}

impl AuthFinding {
    /// Build the policy subject this finding implies. An unverified caller still
    /// becomes a subject - just one with no DID and no capabilities, which the
    /// policy will route to shadow.
    pub fn to_subject(&self, tier: Option<String>, capabilities: Vec<String>) -> Subject {
        if self.valid {
            Subject {
                did: self.holder.clone(),
                tier,
                capabilities,
            }
        } else {
            Subject {
                did: None,
                tier: None,
                capabilities: Vec::new(),
            }
        }
    }
}

/// Assess a presented token against a revocation set. `None` (no token) is a
/// valid, expected case - the caller is simply unauthenticated, not rejected.
pub fn assess(token: Option<&str>, revocation: &RevocationSet) -> AuthFinding {
    let token = match token {
        Some(t) if !t.is_empty() => t,
        _ => {
            return AuthFinding {
                holder: None,
                root_issuer: None,
                valid: false,
                reason: "no token presented".to_string(),
            }
        }
    };

    let result = verify_chain(token, Some(revocation), None);
    if result.valid {
        let holder = result.chain.first().map(|p| p.iss.clone());
        AuthFinding {
            holder,
            root_issuer: result.root_issuer,
            valid: true,
            reason: "verified".to_string(),
        }
    } else {
        AuthFinding {
            holder: None,
            root_issuer: result.root_issuer,
            valid: false,
            reason: result.error.unwrap_or_else(|| "chain did not verify".to_string()),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn missing_token_is_not_an_error_just_unverified() {
        let rev = RevocationSet::new();
        let f = assess(None, &rev);
        assert!(!f.valid);
        assert!(f.holder.is_none());
        // Admit-all: an unverified caller is still allowed to become a subject.
        let subj = f.to_subject(Some("pro".into()), vec!["force_enable".into()]);
        assert!(subj.did.is_none());
        assert!(subj.capabilities.is_empty(), "no creds means no capabilities");
    }

    #[test]
    fn garbage_token_does_not_panic_and_reads_invalid() {
        let rev = RevocationSet::new();
        let f = assess(Some("not.a.ucan"), &rev);
        assert!(!f.valid);
    }
}
